UPDATE events SET description = '<p>Join Sixty Inches From Center at <a href="https://elasticarts.org/" target="_blank" rel="noopener">Elastic Arts</a> to hear the latest from poets and creative writers recently published by Sixty Lit, including <strong>Vera Blossom</strong>, <strong>e’mon lauren</strong>, <strong>Diego Báez</strong>, <strong>Temperance Aghamohammadi</strong>, and <strong>Riley Yaxley.</strong></p>
